const input = $input.first().json;
const binaryParts = $input.first().binary || {};

// Se vier via FormData (binário direto)
if (binaryParts.arquivo_receita) {
    return [{
        json: input,
        binary: {
            data: binaryParts.arquivo_receita
        }
    }];
}

// Suporte para o modo texto antigo (fallback)
let data = input.body || input;
if (typeof data === 'string') {
  try { data = JSON.parse(data); } catch(e) {}
}

return [{ json: data, binary: binaryParts }];
